import { classes, Container } from '@adobe-commerce/elsie/lib';
import { useText } from '@adobe-commerce/elsie/i18n';
import { useSellerAssistedBuyingActivity } from '@/account/hooks/containers/useSellerAssistedBuyingActivity';
import { useGetStoreConfigs } from '@/account/hooks/containers/useGetStoreConfigs';
import { SellerAssistedBuyingActivityProps } from '@/account/types';
import { SellerAssistedBuyingActivityTable } from '@/account/components';

export const SellerAssistedBuyingActivity: Container<
  SellerAssistedBuyingActivityProps
> = ({ className, pageSize = 10, withWrapper = true }) => {
  const translations = useText({
    actionHeader: 'Account.sellerAssistedBuyingActivity.tableHeaders.action',
    dateHeader: 'Account.sellerAssistedBuyingActivity.tableHeaders.date',
    detailsHeader: 'Account.sellerAssistedBuyingActivity.tableHeaders.details',
    emptyStateMessage: 'Account.sellerAssistedBuyingActivity.emptyStateMessage',
    errorMessage: 'Account.sellerAssistedBuyingActivity.errorMessage',
    featureDisabledMessage:
      'Account.sellerAssistedBuyingActivity.featureDisabledMessage',
    // Action types translations
    placeOrder: 'Account.sellerAssistedBuyingActivity.actionTypes.place_order',
    addToCart: 'Account.sellerAssistedBuyingActivity.actionTypes.add_to_cart',
    removeFromCart:
      'Account.sellerAssistedBuyingActivity.actionTypes.remove_from_cart',
    removeCartItem:
      'Account.sellerAssistedBuyingActivity.actionTypes.remove_cart_item',
    updateQty: 'Account.sellerAssistedBuyingActivity.actionTypes.update_qty',
    applyCoupon:
      'Account.sellerAssistedBuyingActivity.actionTypes.apply_coupon',
    removeCoupon:
      'Account.sellerAssistedBuyingActivity.actionTypes.remove_coupon',
    updateAddress:
      'Account.sellerAssistedBuyingActivity.actionTypes.update_address',
    updatePayment:
      'Account.sellerAssistedBuyingActivity.actionTypes.update_payment',
    updateShipping:
      'Account.sellerAssistedBuyingActivity.actionTypes.update_shipping',
    addProductNote:
      'Account.sellerAssistedBuyingActivity.actionTypes.add_product_note',
    updateCustomerInfo:
      'Account.sellerAssistedBuyingActivity.actionTypes.update_customer_info',
    save: 'Account.sellerAssistedBuyingActivity.actionTypes.save',
  });

  const {
    loading,
    adminAssistanceActions,
    error,
    currentPage,
    handlePageChange,
  } = useSellerAssistedBuyingActivity({ pageSize });
  const {
    loading: storeConfigLoading,
    remoteShoppingAssistanceConfigs,
  } = useGetStoreConfigs();

  const tableHeaders = {
    action: translations.actionHeader,
    date: translations.dateHeader,
    details: translations.detailsHeader,
  };

  const actionTypesMap: Record<string, string> = {
    place_order: translations.placeOrder,
    add_to_cart: translations.addToCart,
    remove_from_cart: translations.removeFromCart,
    remove_cart_item: translations.removeCartItem,
    update_qty: translations.updateQty,
    apply_coupon: translations.applyCoupon,
    remove_coupon: translations.removeCoupon,
    update_address: translations.updateAddress,
    update_payment: translations.updatePayment,
    update_shipping: translations.updateShipping,
    add_product_note: translations.addProductNote,
    update_customer_info: translations.updateCustomerInfo,
    save: translations.save,
  };

  return (
    <div
      className={classes([
        'account-seller-assisted-buying-activity',
        className,
      ])}
      data-testid="sellerAssistedBuyingActivityId"
    >
      <SellerAssistedBuyingActivityTable
        loading={storeConfigLoading || loading}
        adminAssistanceActions={adminAssistanceActions}
        tableHeaders={tableHeaders}
        actionTypesMap={actionTypesMap}
        emptyStateMessage={translations.emptyStateMessage}
        featureDisabledMessage={translations.featureDisabledMessage}
        isRemoteShoppingAssistanceAvailable={
          remoteShoppingAssistanceConfigs?.shoppingAssistanceEnabled ?? false
        }
        errorMessage={error ? translations.errorMessage : undefined}
        currentPage={currentPage}
        onPageChange={handlePageChange}
        withWrapper={withWrapper}
      />
    </div>
  );
};
