import { getAdminAssistanceActions } from '@/account/api';
import { useCallback, useEffect, useState } from 'preact/hooks';
import {
  UseSellerAssistedBuyingActivityReturn,
  UseSellerAssistedBuyingActivityProps,
  AdminAssistanceActions,
} from '@/account/types';

export const useSellerAssistedBuyingActivity = (
  props: UseSellerAssistedBuyingActivityProps = {}
): UseSellerAssistedBuyingActivityReturn => {
  const { pageSize = 10 } = props;
  const [loading, setLoading] = useState<boolean>(true);
  const [adminAssistanceActions, setAdminAssistanceActions] =
    useState<AdminAssistanceActions | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [currentPage, setCurrentPage] = useState<number>(1);

  // Reset to page 1 when pageSize changes to avoid out-of-range page requests
  useEffect(() => {
    setCurrentPage(1);
  }, [pageSize]);

  useEffect(() => {
    setLoading(true);
    setError(null);

    getAdminAssistanceActions(pageSize, currentPage)
      .then((adminAssistanceActions) => {
        setAdminAssistanceActions(adminAssistanceActions);
      })
      .catch((err) => {
        console.error('Failed to fetch admin assistance actions:', err);
        setError(err instanceof Error ? err.message : String(err));
      })
      .finally(() => {
        setLoading(false);
      });
  }, [currentPage, pageSize]);

  const handlePageChange = useCallback((page: number) => {
    setCurrentPage(page);
  }, []);

  return {
    loading,
    adminAssistanceActions,
    error,
    currentPage,
    handlePageChange,
  };
};
